UPDATE 
	${targetTable}
SET
	${targetStatusCol} = #{updateStatus}
	,upd_dtime = CURRENT_TIMESTAMP
    ,upd_id = #{userId}
WHERE 1=1
	AND use_yn = 'Y'
	AND ${targetPkCol} = #{refId}
	AND ${targetStatusCol} = #{currentEtpStatus}

UPDATE
	TB_ORDER_MST
SET
	order_status = #{updateStatus}
WHERE 1=1
AND order_id = #{refId}
